import {
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  model,
  output,
  signal,
} from '@angular/core';
import { ControlValueAccessor } from '@angular/forms';
import { injectFormControl } from '../../utils/form-control';
import { LabelComponent } from '../label';
import { SELECT_CONTEXT, type SelectContext } from './select.tokens';

let _selectIdCounter = 0;

@Component({
  selector: 'n-select',
  standalone: true,
  imports: [LabelComponent],
  template: `
    <div class="flex flex-col" data-slot="root">

      @if (nLabel()) {
        <n-label [nId]="labelId()" [nRequired]="nRequired()" [nDisabled]="_isDisabled()">
          {{ nLabel() }}
        </n-label>
      }

      <ng-content />

      @if (nError() && hasError()) {
        <p
          [id]="errorId()"
          class="mt-1 text-xs text-destructive animate-error-in"
          role="alert"
          data-slot="error"
        >
          {{ nError() }}
        </p>
      }

      @if (nHint() && !hasError()) {
        <p
          [id]="hintId()"
          class="mt-1 text-xs text-muted-foreground"
          data-slot="hint"
        >
          {{ nHint() }}
        </p>
      }

    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents', 'data-slot': 'root' },
  providers: [
    {
      provide: SELECT_CONTEXT,
      useFactory: (cmp: SelectComponent) => cmp.context,
      deps: [forwardRef(() => SelectComponent)],
    },
  ],
})
export class SelectComponent implements ControlValueAccessor {
  readonly nValue            = model<string>('');
  readonly nValues           = model<string[]>([]);
  readonly nMultiple         = input<boolean>(false);
  readonly nDisabled         = input<boolean>(false);
  readonly nLoading          = input<boolean>(false);
  readonly nClearable        = input<boolean>(false);
  readonly nSelectAll        = input<boolean>(false);
  readonly nMaxSelections    = input<number | null>(null);
  readonly nMultiSummary     = input<'count' | 'list'>('count');
  readonly nMatchTriggerWidth = input<boolean>(true);
  readonly nId               = input<string>('');

  readonly nLabel     = input<string>('');
  readonly nError     = input<string | null>(null);
  readonly nHint      = input<string | null>(null);
  readonly nRequired  = input<boolean>(false);
  readonly nAriaLabel = input<string>('');

  readonly nOpenChange = output<boolean>();
  readonly nChange     = output<string | string[]>();

  private readonly _staticId   = `n-select-${++_selectIdCounter}`;
  private readonly _form       = injectFormControl<string | string[]>(this);
  private readonly _open       = signal(false);
  private readonly _triggerEl  = signal<HTMLElement | null>(null);
  private readonly _registry   = signal<Map<string, string>>(new Map());
  private readonly _typeAheadActive = signal<string | null>(null);
  private _typeAheadBuffer = '';
  private _typeAheadTimer: ReturnType<typeof setTimeout> | null = null;
  private _navigateHandler: ((direction: 1 | -1) => void) | null = null;
  private _typeAheadHandler: ((value: string) => void) | null = null;

  protected readonly _isDisabled = computed(() => this.nDisabled() || this._form.disabledByForm());
  protected readonly selectId = computed(() => this.nId() || this._staticId);
  protected readonly labelId  = computed(() => `${this.selectId()}-label`);
  protected readonly errorId  = computed(() => `${this.selectId()}-error`);
  protected readonly hintId   = computed(() => `${this.selectId()}-hint`);

  protected readonly hasError = computed(
    () => !!this.nError() || (this._form.controlInvalid() && this._form.controlTouched()),
  );
  protected readonly isRequired  = computed(() => this.nRequired());
  protected readonly describedBy = computed<string | null>(() => {
    if (this.hasError()) return this.errorId();
    if (this.nHint())   return this.hintId();
    return null;
  });

  private readonly _selectedLabel = computed(() => {
    const v = this.nValue();
    if (!v) return '';
    return this._registry().get(v) ?? v;
  });

  private readonly _selectedLabels = computed<Record<string, string>>(() => {
    const map = this._registry();
    const out: Record<string, string> = {};
    for (const v of this.nValues()) out[v] = map.get(v) ?? v;
    return out;
  });

  private readonly _registeredCount = computed(() => this._registry().size);

  readonly context: SelectContext = {
    open: this._open,
    multiple: this.nMultiple,
    disabled: this._isDisabled,
    loading: this.nLoading,
    clearable: this.nClearable,
    selectAll: this.nSelectAll,
    maxSelections: this.nMaxSelections,
    multiSummary: this.nMultiSummary,
    matchTriggerWidth: this.nMatchTriggerWidth,
    value: this.nValue,
    values: this.nValues,
    selectedLabel: this._selectedLabel,
    selectedLabels: this._selectedLabels,
    triggerEl: this._triggerEl.asReadonly(),
    hasError:    this.hasError,
    required:    this.isRequired,
    describedBy: this.describedBy,
    labelId:     this.labelId,
    ariaLabel:   this.nAriaLabel,
    typeAheadActive: this._typeAheadActive.asReadonly(),
    registeredCount: this._registeredCount,
    get triggerId() { return ''; },
    get contentId() { return ''; },
    openPanel: () => {
      if (this._isDisabled()) return;
      this._open.set(true);
      this.nOpenChange.emit(true);
    },
    closePanel: (returnFocus = true) => {
      if (!this._open()) return;
      this._open.set(false);
      this._clearTypeAhead();
      this.nOpenChange.emit(false);
      this._form.notifyTouched();
      if (returnFocus) this._triggerEl()?.focus();
    },
    togglePanel: () => {
      if (this._open()) this.context.closePanel(false);
      else this.context.openPanel();
    },
    selectItem: (value, label) => {
      if (this.nMultiple()) {
        const current = this.nValues();
        const isOn = current.includes(value);
        if (!isOn && !this.context.canSelectMore(value)) return;
        const next = isOn
          ? current.filter(v => v !== value)
          : [...current, value];
        this.nValues.set(next);
        this._form.notifyChange(next);
        this.nChange.emit(next);
      } else {
        this.nValue.set(value);
        this._registerLabel(value, label);
        this._form.notifyChange(value);
        this.nChange.emit(value);
        this.context.closePanel(true);
      }
    },
    clearSelection: () => {
      if (this.nMultiple()) {
        this.nValues.set([]);
        this._form.notifyChange([]);
        this.nChange.emit([]);
      } else {
        this.nValue.set('');
        this._form.notifyChange('');
        this.nChange.emit('');
      }
    },
    selectAllVisible: (values) => {
      if (!this.nMultiple()) return;
      const current = this.nValues();
      const allOn = values.every(v => current.includes(v));
      const next = allOn
        ? current.filter(v => !values.includes(v))
        : Array.from(new Set([...current, ...values]));
      const max = this.nMaxSelections();
      const capped = max != null ? next.slice(0, max) : next;
      this.nValues.set(capped);
      this._form.notifyChange(capped);
      this.nChange.emit(capped);
    },
    isSelected: (value) =>
      this.nMultiple() ? this.nValues().includes(value) : this.nValue() === value,
    canSelectMore: (value) => {
      if (!this.nMultiple()) return true;
      const max = this.nMaxSelections();
      if (max == null) return true;
      const current = this.nValues();
      if (current.includes(value)) return true;
      return current.length < max;
    },
    setTriggerEl: (el) => this._triggerEl.set(el),
    registerItem: (value, label) => {
      this._registry.update(map => {
        const next = new Map(map);
        next.set(value, label);
        return next;
      });
      return () => {
        this._registry.update(map => {
          const next = new Map(map);
          next.delete(value);
          return next;
        });
      };
    },
    navigateItems: (direction) => this._navigateHandler?.(direction),
    setNavigateHandler: (fn) => { this._navigateHandler = fn; },
    typeAhead: (char) => {
      if (!char || char.length !== 1) return;
      this._typeAheadBuffer += char.toLowerCase();
      this._typeAheadActive.set(this._typeAheadBuffer);
      if (this._typeAheadTimer) clearTimeout(this._typeAheadTimer);
      this._typeAheadTimer = setTimeout(() => this._clearTypeAhead(), 600);
      const buffer = this._typeAheadBuffer;
      const match = Array.from(this._registry().entries())
        .find(([, label]) => label.toLowerCase().startsWith(buffer));
      if (match) this._typeAheadHandler?.(match[0]);
    },
    setTypeAheadHandler: (fn) => { this._typeAheadHandler = fn; },
  };

  constructor() {
    Object.defineProperty(this.context, 'triggerId', { get: () => `${this.selectId()}-trigger` });
    Object.defineProperty(this.context, 'contentId', { get: () => `${this.selectId()}-content` });
  }

  private _registerLabel(value: string, label: string): void {
    if (!label) return;
    this._registry.update(map => {
      if (map.get(value) === label) return map;
      const next = new Map(map);
      next.set(value, label);
      return next;
    });
  }

  private _clearTypeAhead(): void {
    this._typeAheadBuffer = '';
    this._typeAheadActive.set(null);
    if (this._typeAheadTimer) {
      clearTimeout(this._typeAheadTimer);
      this._typeAheadTimer = null;
    }
  }

  writeValue(v: string | string[] | null | undefined): void {
    if (Array.isArray(v)) this.nValues.set(v);
    else this.nValue.set(v ?? '');
  }

  registerOnChange(fn: (v: string | string[]) => void): void {
    this._form.setOnChange(fn);
  }

  registerOnTouched(fn: () => void): void {
    this._form.setOnTouched(fn);
  }

  setDisabledState(isDisabled: boolean): void {
    this._form.setDisabledByForm(isDisabled);
  }
}

import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  OnDestroy,
  ViewChild,
  computed,
  inject,
  input,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { SELECT_CONTEXT } from './select.tokens';
import { selectTriggerVariants, type SelectTriggerVariants } from './select.variants';

@Component({
  selector: 'n-select-trigger',
  standalone: true,
  template: `
    <button
      #triggerBtn
      type="button"
      [id]="ctx.triggerId"
      role="combobox"
      aria-haspopup="listbox"
      data-slot="trigger"
      [attr.aria-expanded]="ctx.open()"
      [attr.aria-controls]="ctx.contentId"
      [attr.aria-busy]="ctx.loading() ? true : null"
      [attr.aria-disabled]="ctx.disabled() ? true : null"
      [attr.disabled]="ctx.disabled() ? true : null"
      [attr.data-disabled]="ctx.disabled() ? '' : null"
      [attr.aria-labelledby]="ctx.labelId() || null"
      [attr.aria-label]="ctx.labelId() ? null : (ctx.ariaLabel() || null)"
      [attr.aria-invalid]="ctx.hasError() ? true : null"
      [attr.data-invalid]="ctx.hasError() ? '' : null"
      [attr.aria-required]="ctx.required() ? true : null"
      [attr.aria-describedby]="ctx.describedBy()"
      [attr.data-state]="ctx.open() ? 'open' : 'closed'"
      [class]="classes()"
      (click)="handleClick()"
      (keydown)="handleKeydown($event)"
    >
      <span class="flex flex-1 items-center gap-2 truncate text-left"
            [class.text-muted-foreground]="!hasValue()">
        @if (ctx.multiple() && hasValue() && ctx.multiSummary() === 'list') {
          <span class="truncate">{{ multiList() }}</span>
        } @else {
          <span class="truncate">{{ displayText() }}</span>
        }
      </span>

      <span class="ml-auto flex shrink-0 items-center gap-1">
        @if (ctx.clearable() && hasValue() && !ctx.loading() && !ctx.disabled()) {
          <span
            role="button"
            tabindex="-1"
            class="rounded-sm opacity-50 hover:opacity-100 focus:outline-none focus:ring-1 focus:ring-ring"
            aria-label="Clear selection"
            data-slot="icon-trailing"
            (click)="handleClear($event)"
            (keydown)="handleClearKey($event)"
          >
            <svg xmlns="http://www.w3.org/2000/svg" class="h-4 w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true">
              <line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/>
            </svg>
          </span>
        }
        @if (ctx.loading()) {
          <svg class="h-4 w-4 animate-spin text-muted-foreground" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" aria-hidden="true" data-slot="icon-trailing">
            <circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"/>
            <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
          </svg>
        } @else {
          <svg xmlns="http://www.w3.org/2000/svg" class="h-4 w-4 opacity-50 transition-transform"
               [class.rotate-180]="ctx.open()"
               viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true" data-slot="icon-trailing">
            <polyline points="6 9 12 15 18 9"/>
          </svg>
        }
      </span>
    </button>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents' },
})
export class SelectTriggerComponent implements AfterViewInit, OnDestroy {
  readonly nSize = input<SelectTriggerVariants['nSize']>('default');
  readonly nPlaceholder = input<string>('Select an option...');
  readonly nClass = input<string>('');

  protected readonly ctx = inject(SELECT_CONTEXT);

  @ViewChild('triggerBtn') private _triggerBtnRef!: ElementRef<HTMLButtonElement>;

  protected readonly classes = computed(() =>
    mergeClasses(selectTriggerVariants({ nSize: this.nSize() }), this.nClass()),
  );

  protected readonly hasValue = computed(() =>
    this.ctx.multiple() ? this.ctx.values().length > 0 : !!this.ctx.value(),
  );

  protected readonly displayText = computed(() => {
    if (this.ctx.multiple()) {
      const count = this.ctx.values().length;
      return count > 0 ? `${count} selected` : this.nPlaceholder();
    }
    return this.ctx.selectedLabel() || this.ctx.value() || this.nPlaceholder();
  });

  protected readonly multiList = computed(() => {
    const labels = this.ctx.selectedLabels();
    const order = this.ctx.values();
    return order.map(v => labels[v] ?? v).join(', ');
  });

  ngAfterViewInit(): void {
    this.ctx.setTriggerEl(this._triggerBtnRef.nativeElement);
  }

  ngOnDestroy(): void {
    this.ctx.setTriggerEl(null);
  }

  protected handleClick(): void {
    if (this.ctx.disabled()) return;
    this.ctx.togglePanel();
  }

  protected handleKeydown(event: KeyboardEvent): void {
    if (this.ctx.disabled()) return;

    if (!this.ctx.open()) {
      switch (event.key) {
        case 'Enter':
        case ' ':
        case 'ArrowDown':
        case 'ArrowUp':
          event.preventDefault();
          this.ctx.openPanel();
          return;
      }
      if (this._isPrintable(event)) {
        event.preventDefault();
        this.ctx.openPanel();
        queueMicrotask(() => this.ctx.typeAhead(event.key));
      }
    }
  }

  protected handleClear(event: Event): void {
    event.stopPropagation();
    this.ctx.clearSelection();
  }

  protected handleClearKey(event: KeyboardEvent): void {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      event.stopPropagation();
      this.ctx.clearSelection();
    }
  }

  private _isPrintable(event: KeyboardEvent): boolean {
    return event.key.length === 1 && !event.ctrlKey && !event.metaKey && !event.altKey;
  }
}

import { FocusKeyManager } from '@angular/cdk/a11y';
import {
  ConnectedPosition,
  Overlay,
  OverlayConfig,
  OverlayRef,
} from '@angular/cdk/overlay';
import { TemplatePortal } from '@angular/cdk/portal';
import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  OnDestroy,
  TemplateRef,
  ViewChild,
  ViewContainerRef,
  computed,
  contentChildren,
  effect,
  inject,
  input,
} from '@angular/core';
import { Subscription } from 'rxjs';
import { mergeClasses } from '../../utils/merge-classes';
import { SelectItemComponent } from './select-item.component';
import { SELECT_CONTEXT } from './select.tokens';
import { selectContentVariants } from './select.variants';

type Side = 'top' | 'bottom' | 'left' | 'right';
type Align = 'start' | 'center' | 'end';

@Component({
  selector: 'n-select-content',
  standalone: true,
  template: `
    <ng-template #panel>
      <div
        #panelEl
        [id]="ctx.contentId"
        role="listbox"
        tabindex="-1"
        data-slot="content"
        [attr.aria-labelledby]="ctx.labelId() || ctx.triggerId"
        [attr.aria-multiselectable]="ctx.multiple() ? true : null"
        [attr.data-side]="nSide()"
        [attr.data-state]="ctx.open() ? 'open' : 'closed'"
        [class]="classes()"
        (keydown)="handleKeydown($event)"
      >
        @if (ctx.loading()) {
          <div class="flex flex-col gap-1 p-1" data-slot="loading">
            <div class="h-7 animate-pulse rounded-sm bg-muted"></div>
            <div class="h-7 animate-pulse rounded-sm bg-muted"></div>
            <div class="h-7 animate-pulse rounded-sm bg-muted"></div>
          </div>
        } @else {
          @if (ctx.multiple() && ctx.selectAll()) {
            <button
              type="button"
              role="option"
              tabindex="-1"
              data-slot="select-all"
              class="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 text-sm font-medium outline-none transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground"
              [attr.aria-selected]="allSelected()"
              (click)="handleSelectAll()"
              (keydown)="handleSelectAllKey($event)"
            >
              <span class="flex w-4 shrink-0 items-center justify-center" aria-hidden="true">
                @if (allSelected()) {
                  <svg xmlns="http://www.w3.org/2000/svg" class="h-4 w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                    <polyline points="20 6 9 17 4 12"/>
                  </svg>
                } @else if (someSelected()) {
                  <svg xmlns="http://www.w3.org/2000/svg" class="h-4 w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                    <line x1="5" y1="12" x2="19" y2="12"/>
                  </svg>
                }
              </span>
              <span class="flex-1 text-left">{{ allSelected() ? 'Deselect all' : 'Select all' }}</span>
              <span class="text-xs text-muted-foreground">{{ ctx.values().length }}/{{ items().length }}</span>
            </button>
            <div class="my-1 h-px bg-border" role="separator" aria-hidden="true"></div>
          }

          <ng-content />
        }
      </div>
    </ng-template>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents' },
})
export class SelectContentComponent implements AfterViewInit, OnDestroy {
  readonly nSide = input<Side>('bottom');
  readonly nAlign = input<Align>('start');
  readonly nSideOffset = input<number>(4);
  readonly nAlignOffset = input<number>(0);
  readonly nClass = input<string>('');

  protected readonly ctx = inject(SELECT_CONTEXT);
  private readonly _overlay = inject(Overlay);
  private readonly _vcr = inject(ViewContainerRef);

  protected readonly items = contentChildren(SelectItemComponent, { descendants: true });

  @ViewChild('panel', { static: true }) private _panelTpl!: TemplateRef<unknown>;
  @ViewChild('panelEl') private _panelEl?: ElementRef<HTMLElement>;

  private _overlayRef: OverlayRef | null = null;
  private _portal: TemplatePortal | null = null;
  private _keyManager: FocusKeyManager<SelectItemComponent> | null = null;
  private _backdropSub?: Subscription;

  protected readonly classes = computed(() =>
    mergeClasses(selectContentVariants(), this.nClass()),
  );

  protected readonly allSelected = computed(() => {
    const its = this.items();
    if (its.length === 0) return false;
    const vals = this.ctx.values();
    return its.every(it => vals.includes(it.nValue()));
  });

  protected readonly someSelected = computed(() => {
    const vals = this.ctx.values();
    return vals.length > 0 && !this.allSelected();
  });

  constructor() {
    effect(() => {
      if (this.ctx.open()) this.attach();
      else this.detach();
    });
  }

  ngAfterViewInit(): void {
    this._portal = new TemplatePortal(this._panelTpl, this._vcr);
  }

  ngOnDestroy(): void {
    this.detach();
  }

  private attach(): void {
    const trigger = this.ctx.triggerEl();
    if (!trigger || !this._portal) return;
    if (this._overlayRef?.hasAttached()) return;

    const width = trigger.getBoundingClientRect().width;
    const positions = this.buildPositions();
    const config = new OverlayConfig({
      minWidth: this.ctx.matchTriggerWidth() ? width : undefined,
      positionStrategy: this._overlay
        .position()
        .flexibleConnectedTo(trigger)
        .withPositions(positions)
        .withFlexibleDimensions(false)
        .withPush(true),
      scrollStrategy: this._overlay.scrollStrategies.reposition(),
      hasBackdrop: true,
      backdropClass: 'cdk-overlay-transparent-backdrop',
    });

    this._overlayRef = this._overlay.create(config);
    this._overlayRef.attach(this._portal);
    this._backdropSub = this._overlayRef.backdropClick().subscribe(() => this.ctx.closePanel(false));

    queueMicrotask(() => {
      const items = this.items();
      this._keyManager = new FocusKeyManager<SelectItemComponent>(items)
        .withWrap()
        .withVerticalOrientation()
        .skipPredicate((item: SelectItemComponent) => item.isDisabled());
      this.ctx.setNavigateHandler(direction => {
        if (direction === 1) this._keyManager!.setNextItemActive();
        else this._keyManager!.setPreviousItemActive();
      });
      this.ctx.setTypeAheadHandler(value => {
        const idx = items.findIndex(it => it.nValue() === value);
        if (idx >= 0) this._keyManager!.setActiveItem(idx);
      });
      this._focusInitial();
    });
  }

  private _focusInitial(): void {
    const items = this.items();
    if (items.length === 0 || !this._keyManager) return;
    if (this.ctx.multiple()) {
      this._keyManager.setFirstItemActive();
      return;
    }
    const value = this.ctx.value();
    const idx = items.findIndex(it => it.nValue() === value);
    if (idx >= 0) this._keyManager.setActiveItem(idx);
    else this._keyManager.setFirstItemActive();
  }

  private detach(): void {
    this._backdropSub?.unsubscribe();
    this._backdropSub = undefined;
    this.ctx.setNavigateHandler(null);
    this.ctx.setTypeAheadHandler(null);
    this._keyManager = null;
    if (this._overlayRef?.hasAttached()) this._overlayRef.detach();
    this._overlayRef?.dispose();
    this._overlayRef = null;
  }

  protected handleKeydown(event: KeyboardEvent): void {
    if (event.key === 'Escape') {
      event.preventDefault();
      this.ctx.closePanel(true);
      return;
    }
    if (event.key === 'Tab') {
      this.ctx.closePanel(false);
      return;
    }
    if (this._isPrintable(event)) {
      this.ctx.typeAhead(event.key);
      return;
    }
    this._keyManager?.onKeydown(event);
  }

  protected handleSelectAll(): void {
    const visible = this.items().filter(it => !it.nDisabled()).map(it => it.nValue());
    this.ctx.selectAllVisible(visible);
  }

  protected handleSelectAllKey(event: KeyboardEvent): void {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      this.handleSelectAll();
    }
  }

  private _isPrintable(event: KeyboardEvent): boolean {
    return event.key.length === 1 && !event.ctrlKey && !event.metaKey && !event.altKey;
  }

  private buildPositions(): ConnectedPosition[] {
    const side = this.nSide();
    const align = this.nAlign();
    const sideOffset = this.nSideOffset();
    const alignOffset = this.nAlignOffset();

    const buildOne = (s: Side, a: Align): ConnectedPosition => {
      const isVertical = s === 'top' || s === 'bottom';
      const originY = s === 'bottom' ? 'bottom' : s === 'top' ? 'top' : 'center';
      const overlayY = s === 'bottom' ? 'top' : s === 'top' ? 'bottom' : 'center';
      const originX =
        s === 'right' ? 'end' : s === 'left' ? 'start' : a === 'center' ? 'center' : a;
      const overlayX =
        s === 'right' ? 'start' : s === 'left' ? 'end' : a === 'center' ? 'center' : a;
      return {
        originX: originX as ConnectedPosition['originX'],
        originY: originY as ConnectedPosition['originY'],
        overlayX: overlayX as ConnectedPosition['overlayX'],
        overlayY: overlayY as ConnectedPosition['overlayY'],
        offsetX: isVertical ? alignOffset : s === 'right' ? sideOffset : -sideOffset,
        offsetY: isVertical ? (s === 'bottom' ? sideOffset : -sideOffset) : alignOffset,
      };
    };

    const opposite: Record<Side, Side> = {
      top: 'bottom',
      bottom: 'top',
      left: 'right',
      right: 'left',
    };
    return [buildOne(side, align), buildOne(opposite[side], align)];
  }
}

import { FocusableOption } from '@angular/cdk/a11y';
import {
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  HostListener,
  OnDestroy,
  OnInit,
  computed,
  inject,
  input,
  signal,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { SELECT_CONTEXT } from './select.tokens';
import { selectItemVariants, type SelectItemVariants } from './select.variants';

@Component({
  selector: 'n-select-item',
  standalone: true,
  template: `
    <ng-content select="[data-slot=icon-leading]" />

    <span class="flex flex-1 flex-col leading-tight min-w-0">
      <span class="truncate">
        @if (nLabel()) { {{ nLabel() }} } @else { <ng-content /> }
      </span>
      @if (nDescription()) {
        <span class="truncate text-xs text-muted-foreground" data-slot="description">
          {{ nDescription() }}
        </span>
      }
    </span>

    <span class="flex w-4 shrink-0 items-center justify-center" aria-hidden="true">
      @if (isSelected()) {
        <svg xmlns="http://www.w3.org/2000/svg" class="h-4 w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
          <polyline points="20 6 9 17 4 12"/>
        </svg>
      }
    </span>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    role: 'option',
    tabindex: '-1',
    'data-slot': 'item',
    '[class]': 'classes()',
    '[attr.aria-selected]': 'isSelected()',
    '[attr.aria-disabled]': 'isDisabled() ? true : null',
    '[attr.data-disabled]': 'isDisabled() ? "" : null',
    '[attr.data-highlighted]': 'highlighted() ? "" : null',
    '[attr.data-value]': 'nValue()',
    '(click)': 'handleSelect()',
    '(keydown)': 'handleKeydown($event)',
    '(mouseenter)': 'setHighlighted(true)',
    '(mouseleave)': 'setHighlighted(false)',
  },
})
export class SelectItemComponent implements FocusableOption, OnInit, OnDestroy {
  readonly nValue = input.required<string>();
  readonly nLabel = input<string>('');
  readonly nDescription = input<string>('');
  readonly nDisabled = input<boolean>(false);
  readonly nVariant = input<SelectItemVariants['nVariant']>('default');
  readonly nClass = input<string>('');

  readonly host = inject<ElementRef<HTMLElement>>(ElementRef);
  protected readonly ctx = inject(SELECT_CONTEXT);
  private readonly _highlighted = signal(false);
  private _unregister: (() => void) | null = null;

  readonly highlighted = this._highlighted.asReadonly();

  readonly isSelected = computed(() => this.ctx.isSelected(this.nValue()));

  readonly isDisabled = computed(() => {
    if (this.nDisabled()) return true;
    if (!this.ctx.canSelectMore(this.nValue())) return true;
    return false;
  });

  get disabled(): boolean {
    return this.isDisabled();
  }

  focus(): void {
    this.host.nativeElement.focus({ preventScroll: false });
    this.host.nativeElement.scrollIntoView({ block: 'nearest' });
  }

  getLabel(): string {
    return this.nLabel() || (this.host.nativeElement.textContent?.trim() ?? '');
  }

  protected readonly classes = computed(() =>
    mergeClasses(selectItemVariants({ nVariant: this.nVariant() }), this.nClass()),
  );

  ngOnInit(): void {
    this._unregister = this.ctx.registerItem(this.nValue(), this.getLabel());
  }

  ngOnDestroy(): void {
    this._unregister?.();
  }

  setHighlighted(value: boolean): void {
    if (this.isDisabled()) return;
    this._highlighted.set(value);
    if (value) this.host.nativeElement.focus({ preventScroll: true });
  }

  protected handleSelect(): void {
    if (this.isDisabled()) return;
    this.ctx.selectItem(this.nValue(), this.getLabel());
  }

  protected handleKeydown(event: KeyboardEvent): void {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      this.handleSelect();
    } else if (event.key === 'Escape') {
      event.preventDefault();
      this.ctx.closePanel(true);
    }
  }

  @HostListener('focus') onFocus(): void {
    if (!this.isDisabled()) this._highlighted.set(true);
  }

  @HostListener('blur') onBlur(): void {
    this._highlighted.set(false);
  }
}

